        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "spell mishap",
            damages: [{ itemType: "amulet", amount: 250 }],
          },
        },
      ],
    });
    expect(result.results).toEqual([
      { premium: 59 },
      { payout: 100, remainingCap: 1100 },
      { payout: 150, remainingCap: 950 },
